bool esCaucasico(vector<int>& v, int inicio, int fin) {
  if (fin - inicio <= 1) return true; // Caso base
  int mitad = (inicio + fin) / 2;
  // Contar pares en cada mitad
  int paresIzq = contarPares(v, inicio, mitad);
  int paresDer = contarPares(v, mitad, fin);
  // Verificar condiciÃģn de caucÃĄsico
  if (abs(paresIzq - paresDer) > 2) return false;
  // Llamadas recursivas
  return esCaucasico(v, inicio, mitad) && esCaucasico(v, mitad, fin);
}

int contarPares(vector<int>& v, int inicio, int fin) {
  int count = 0;
  for (int i = inicio; i < fin; ++i) {
    if (v[i] % 2 == 0) ++count;
  }
  return count;
}
